(window.webpackJsonp=window.webpackJsonp||[]).push([[63],{1338:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Initialize your data structure here.\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> MyHashMap = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.hash={}\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * value will always be non-negative. \\n * @param {number} key \\n * @param {number} value\\n * @return {void}\\n */</span>\\nMyHashMap.prototype.put = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">key, value</span>) </span>{\\n    <span class=\\"hljs-keyword\\">this</span>.hash[key]=value\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Returns the value to which the specified key is mapped, or -1 if this map contains no mapping for the key \\n * @param {number} key\\n * @return {number}\\n */</span>\\nMyHashMap.prototype.get = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">key</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.hash[key]==<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.hash[key]\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Removes the mapping of the specified value key if this map contains a mapping for the key \\n * @param {number} key\\n * @return {void}\\n */</span>\\nMyHashMap.prototype.remove = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">key</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.hash[key]!=<span class=\\"hljs-literal\\">null</span>){\\n    <span class=\\"hljs-keyword\\">delete</span>(<span class=\\"hljs-keyword\\">this</span>.hash[key])\\n  }\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your MyHashMap object will be instantiated and called as such:\\n * var obj = Object.create(MyHashMap).createNew()\\n * obj.put(key,value)\\n * var param_2 = obj.get(key)\\n * obj.remove(key)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"design-hashmap","hasThinking":false,"content":"<p>\u4e0d\u4f7f\u7528\u4efb\u4f55\u5185\u5efa\u7684\u54c8\u5e0c\u8868\u5e93\u8bbe\u8ba1\u4e00\u4e2a\u54c8\u5e0c\u6620\u5c04\uff08HashMap\uff09\u3002</p>\\n\\n<p>\u5b9e\u73b0 <code>MyHashMap</code> \u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>MyHashMap()</code> \u7528\u7a7a\u6620\u5c04\u521d\u59cb\u5316\u5bf9\u8c61</li>\\n\\t<li><code>void put(int key, int value)</code> \u5411 HashMap \u63d2\u5165\u4e00\u4e2a\u952e\u503c\u5bf9 <code>(key, value)</code> \u3002\u5982\u679c <code>key</code> \u5df2\u7ecf\u5b58\u5728\u4e8e\u6620\u5c04\u4e2d\uff0c\u5219\u66f4\u65b0\u5176\u5bf9\u5e94\u7684\u503c <code>value</code> \u3002</li>\\n\\t<li><code>int get(int key)</code> \u8fd4\u56de\u7279\u5b9a\u7684 <code>key</code> \u6240\u6620\u5c04\u7684 <code>value</code> \uff1b\u5982\u679c\u6620\u5c04\u4e2d\u4e0d\u5305\u542b <code>key</code> \u7684\u6620\u5c04\uff0c\u8fd4\u56de <code>-1</code> \u3002</li>\\n\\t<li><code>void remove(key)</code> \u5982\u679c\u6620\u5c04\u4e2d\u5b58\u5728 <code>key</code> \u7684\u6620\u5c04\uff0c\u5219\u79fb\u9664 <code>key</code> \u548c\u5b83\u6240\u5bf9\u5e94\u7684 <code>value</code> \u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165</strong>\uff1a\\n[\\"MyHashMap\\", \\"put\\", \\"put\\", \\"get\\", \\"get\\", \\"put\\", \\"get\\", \\"remove\\", \\"get\\"]\\n[[], [1, 1], [2, 2], [1], [3], [2, 1], [2], [2], [2]]\\n<strong>\u8f93\u51fa</strong>\uff1a\\n[null, null, null, 1, -1, null, 1, null, -1]\\n\\n<strong>\u89e3\u91ca</strong>\uff1a\\nMyHashMap myHashMap = new MyHashMap();\\nmyHashMap.put(1, 1); // myHashMap \u73b0\u5728\u4e3a [[1,1]]\\nmyHashMap.put(2, 2); // myHashMap \u73b0\u5728\u4e3a [[1,1], [2,2]]\\nmyHashMap.get(1);    // \u8fd4\u56de 1 \uff0cmyHashMap \u73b0\u5728\u4e3a [[1,1], [2,2]]\\nmyHashMap.get(3);    // \u8fd4\u56de -1\uff08\u672a\u627e\u5230\uff09\uff0cmyHashMap \u73b0\u5728\u4e3a [[1,1], [2,2]]\\nmyHashMap.put(2, 1); // myHashMap \u73b0\u5728\u4e3a [[1,1], [2,1]]\uff08\u66f4\u65b0\u5df2\u6709\u7684\u503c\uff09\\nmyHashMap.get(2);    // \u8fd4\u56de 1 \uff0cmyHashMap \u73b0\u5728\u4e3a [[1,1], [2,1]]\\nmyHashMap.remove(2); // \u5220\u9664\u952e\u4e3a 2 \u7684\u6570\u636e\uff0cmyHashMap \u73b0\u5728\u4e3a [[1,1]]\\nmyHashMap.get(2);    // \u8fd4\u56de -1\uff08\u672a\u627e\u5230\uff09\uff0cmyHashMap \u73b0\u5728\u4e3a [[1,1]]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= key, value <= 10<sup>6</sup></code></li>\\n\\t<li>\u6700\u591a\u8c03\u7528 <code>10<sup>4</sup></code> \u6b21 <code>put</code>\u3001<code>get</code> \u548c <code>remove</code> \u65b9\u6cd5</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u4f60\u80fd\u5426\u4e0d\u4f7f\u7528\u5185\u7f6e\u7684 HashMap \u5e93\u89e3\u51b3\u6b64\u95ee\u9898\uff1f</p>\\n","title":"706. \u8bbe\u8ba1\u54c8\u5e0c\u6620\u5c04","relatedTags":["\u8bbe\u8ba1","\u54c8\u5e0c\u8868"],"difficult":"Easy","lang":["javascript"],"uniqueID":"706"}')}}]);